import javax.naming.Context;
import javax.naming.NamingEnumeration;
import javax.naming.NamingException;
import javax.naming.directory.Attribute;
import javax.naming.directory.Attributes;
import javax.naming.directory.DirContext;
import javax.naming.directory.InitialDirContext;
import javax.naming.directory.SearchControls;
import javax.naming.directory.SearchResult;

public class LDAPUserSearch {

    public static Map<String, String> searchUser(String username, String ldapUrl, String ldapUsername, String ldapPassword) {
        try {
            // Set up the LDAP connection properties
            System.setProperty(Context.INITIAL_CONTEXT_FACTORY, "com.sun.jndi.ldap.LdapCtxFactory");
            System.setProperty(Context.PROVIDER_URL, ldapUrl);
            System.setProperty(Context.SECURITY_AUTHENTICATION, "simple");

            // Create an initial context to connect to the LDAP server
            DirContext ctx = new InitialDirContext(new javax.naming.Context() {
                @Override
                public Object lookup(String name) throws NamingException {
                    return null;
                }
            }, ldapUsername, ldapPassword);

            // Define the search filter and attributes to retrieve
            String searchFilter = "(&(objectClass=user)(sAMAccountName=" + username + "))";
            String[] attributeIds = {"mail", "cn", "department"};

            // Create a search controls object to customize the search
            SearchControls searchCtls = new SearchControls();
            searchCtls.setSearchScope(SearchControls.SUBTREE_SCOPE);
            searchCtls.setReturningAttributes(attributeIds);

            // Perform the LDAP search
            NamingEnumeration<SearchResult> results = ctx.search("", searchFilter, searchCtls);

            // Check if any users were found
            if (results.hasMore()) {
                SearchResult result = results.next();
                Attributes attrs = result.getAttributes();

                // Extract user attributes from the result
                Map<String, String> userAttributes = new HashMap<>();
                for (Attribute attr : attrs.getAll()) {
                    userAttributes.put(attr.getID(), (String) attr.get());
                }

                return userAttributes;
            } else {
                System.out.println("No users found with username " + username);
                return null;
            }
        } catch (NamingException e) {
            System.out.println("LDAP connection failed: " + e.getMessage());
            return null;
        }
    }
}